insert into exhibition (id, slug, name, venue, description, start_date, end_date, cover_image_url, map_image_url, map_width, map_height, tips, organizer_id, created_at) values
  ('exh_sibf_2026', 'sibf-2026', '2026 서울국제도서전', '코엑스 A·B1홀, 서울 (COEX Hall A & B1)', '‘한 걸음(One Small Step)’을 주제로 열리는 국내 최대 규모의 책 축제. 국내외 출판사·작가가 한자리에 모여 신간과 굿즈, 주제 강연·전시·낭독회를 선보입니다. A홀과 B1홀에서 수백 개 부스를 만나보세요.', '2026-06-24', '2026-06-28', null, null, 980, 1320, '{"transportation":"지하철 2호선 삼성역 5·6번 출구 또는 9호선 봉은사역에서 코엑스로 연결. A·B1홀은 코엑스 1층입니다.","parking":"코엑스 지하주차장 이용. 도서전 기간 매우 혼잡하니 대중교통을 권장합니다.","ticket":"온라인 예매 및 현장 구매. 단체 티켓 구매 신청서 마감 6/8. 문의 sibf@sibf.kr / 02-702-0670(내선 4254).","guide":"운영시간 11:00–20:00. 주제 강연, 기획 전시, 작가 사인회·낭독회, 해외관(프랑스·캐나다 등)을 즐겨보세요."}'::jsonb, 'org_sibf', '2026-01-02T00:00:00.000Z')
